#include <stdio.h>
#include <string.h>

int unique_char_count(char s[]) {
    int count = 0;
    int freq[256] = {0}; // Array to keep track of character frequency
    int len = strlen(s);

    for (int i = 0; i < len; i++) {
        if (freq[(int)s[i]] == 0) {
            count++;
            freq[(int)s[i]] = 1;
        }
    }
    return count;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        char s[100001]; // Assuming a max string length of 100000
        scanf("%s", s);
        printf("%d\n", unique_char_count(s));
    }
    return 0;
}

code.Java:
import java.util.HashSet;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        sc.nextLine(); // To consume the newline character after the integer input
        while (t-- > 0) {
            String s = sc.nextLine();
            int n = s.length();
            HashSet<Character> st = new HashSet<>();
            for (int i = 0; i < n; i++) {
                st.add(s.charAt(i));
            }
            System.out.println(st.size());
        }
        sc.close();
    }
}

code.JavaScript:
const readline = require('readline');

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

let input = [];
rl.on('line', (line) => {
    input.push(line.trim());
});

rl.on('close', () => {
    let t = parseInt(input[0]);
    for (let i = 1; i <= t; i++) {
        let s = input[i];
        let uniqueChars = new Set(s);
        console.log(uniqueChars.size);
    }
});
